code.JavaScript:
const readline = require('readline').createInterface({
  input: process.stdin,
  output: process.stdout
});
readline.on('line', (line) => {
  const Y = parseInt(line, 10);
  if ((Y % 400 === 0) || ((Y % 4 === 0) && (Y % 100 !== 0)))
    console.log('YES');
  else
    console.log('NO');
});
